__kernel void dynproc_kernel(
    int pyramid_height,
    __global const int* wall,
    __global const int* src_buffer,
    __global int* dst_buffer,
    int cols,
    int rows,
    int t_offset,
    int borderCols,
    int theHalo,
    __local int* local_src,
    __local int* local_dst,
    __global int* outputBuffer)
{
    int idx = get_global_id(0);

    if (idx >= cols) return;

    // Process pyramid_height rows
    for (int h = 0; h < pyramid_height; h++) {
        int row = t_offset + h;
        if (row >= rows - 1) break;

        int min = src_buffer[idx];

        // Check left neighbor
        if (idx > 0) {
            int left = src_buffer[idx - 1];
            if (left < min) min = left;
        }

        // Check right neighbor
        if (idx < cols - 1) {
            int right = src_buffer[idx + 1];
            if (right < min) min = right;
        }

        // Compute new value: wall[row][idx] + min
        dst_buffer[idx] = wall[row * cols + idx] + min;
    }
}
